@import "tailwindcss";
@import "tw-animate-css";

@custom-variant dark (&:is(.dark *));

/*
 * ModernUI theme — sourced from Figma Dev-Ready Designs palette
 * https://www.figma.com/design/gjpoz1ULnuPYTdTZm9Zj0X?node-id=625-22446
 *
 * Blacks:  Primary #242422 | Secondary #595959 | Tertiary #8C8C8C | Quaternary #BFBFBF
 * Greys:   Grey 16 #D6D6D6 | Grey 8 #EBEBEB | Grey 4 #F5F5F5 | Grey 2 #FAFAFA | White #FFFFFF
 * Brand:   Slate #242422 | Dark Teal #009293 | Cream #EDE9E5
 *          Cream BG 1–3 #F2EFEC #F6F4F2 #F9F8F7 | Teal BG 1–2 #D6EDED #E5F4F4
 */

@theme inline {
  /* Semantic — surfaces & actions */
  --color-background: var(--background);
  --color-foreground: var(--foreground);
  --color-card: var(--card);
  --color-card-foreground: var(--card-foreground);
  --color-popover: var(--popover);
  --color-popover-foreground: var(--popover-foreground);
  --color-primary: var(--primary);
  --color-primary-foreground: var(--primary-foreground);
  --color-secondary: var(--secondary);
  --color-secondary-foreground: var(--secondary-foreground);
  --color-muted: var(--muted);
  --color-muted-foreground: var(--muted-foreground);
  --color-accent: var(--accent);
  --color-accent-foreground: var(--accent-foreground);
  --color-destructive: var(--destructive);
  --color-destructive-foreground: var(--destructive-foreground);
  --color-border: var(--border);
  --color-input: var(--input);
  --color-ring: var(--ring);

  /* Brand extensions */
  --color-brand: var(--brand);
  --color-brand-foreground: var(--brand-foreground);
  --color-cream: var(--cream);
  --color-teal-bg: var(--teal-bg);

  /* Figma brand & surfaces */
  --color-slate: var(--slate);
  --color-dark-teal: var(--dark-teal);
  --color-cream-bg-1: var(--cream-bg-1);
  --color-cream-bg-2: var(--cream-bg-2);
  --color-cream-bg-3: var(--cream-bg-3);
  --color-teal-bg-1: var(--teal-bg-1);
  --color-teal-bg-2: var(--teal-bg-2);

  /* Figma blacks (ink scale) */
  --color-black-primary: var(--black-primary);
  --color-black-secondary: var(--black-secondary);
  --color-black-tertiary: var(--black-tertiary);
  --color-black-quaternary: var(--black-quaternary);

  /* Figma greys */
  --color-grey-16: var(--grey-16);
  --color-grey-8: var(--grey-8);
  --color-grey-4: var(--grey-4);
  --color-grey-2: var(--grey-2);
  --color-white: var(--white);

  /* Text scale */
  --color-text-primary: var(--text-primary);
  --color-text-secondary: var(--text-secondary);
  --color-text-tertiary: var(--text-tertiary);
  --color-text-quaternary: var(--text-quaternary);

  /* Charts */
  --color-chart-1: var(--chart-1);
  --color-chart-2: var(--chart-2);
  --color-chart-3: var(--chart-3);
  --color-chart-4: var(--chart-4);
  --color-chart-5: var(--chart-5);

  /* Sidebar */
  --color-sidebar: var(--sidebar);
  --color-sidebar-foreground: var(--sidebar-foreground);
  --color-sidebar-primary: var(--sidebar-primary);
  --color-sidebar-primary-foreground: var(--sidebar-primary-foreground);
  --color-sidebar-accent: var(--sidebar-accent);
  --color-sidebar-accent-foreground: var(--sidebar-accent-foreground);
  --color-sidebar-border: var(--sidebar-border);
  --color-sidebar-ring: var(--sidebar-ring);

  /* DataOS UI — quality states */
  --color-dataos-surface: var(--dataos-surface);
  --color-dataos-success-bg: var(--dataos-success-bg);
  --color-dataos-success-fg: var(--dataos-success-fg);
  --color-dataos-warn-bg: var(--dataos-warn-bg);
  --color-dataos-warn-fg: var(--dataos-warn-fg);
  --color-dataos-fail-bg: var(--dataos-fail-bg);
  --color-dataos-fail-fg: var(--dataos-fail-fg);

  /* Typography & radius */
  --font-sans: var(--font-geist-sans);
  --font-mono: var(--font-geist-mono);
  --radius-sm: calc(var(--radius) - 4px);
  --radius-md: calc(var(--radius) - 2px);
  --radius-lg: var(--radius);
  --radius-xl: calc(var(--radius) + 4px);
}

:root {
  --radius: 0.5rem;

  /* Figma brand & surfaces */
  --slate: #242422;
  --dark-teal: #009293;
  --cream: #ede9e5;
  --cream-bg-1: #f2efec;
  --cream-bg-2: #f6f4f2;
  --cream-bg-3: #f9f8f7;
  --teal-bg-1: #d6eded;
  --teal-bg-2: #e5f4f4;

  /* Figma blacks */
  --black-primary: #242422;
  --black-secondary: #595959;
  --black-tertiary: #8c8c8c;
  --black-quaternary: #bfbfbf;

  /* Figma greys */
  --grey-16: #d6d6d6;
  --grey-8: #ebebeb;
  --grey-4: #f5f5f5;
  --grey-2: #fafafa;
  --white: #ffffff;

  /* Surfaces — warm cream backgrounds */
  --background: var(--cream-bg-3);
  --foreground: var(--slate);
  --card: var(--white);
  --card-foreground: var(--slate);
  --popover: var(--white);
  --popover-foreground: var(--slate);

  /* Brand — Dark Teal primary, Slate ink */
  --primary: var(--dark-teal);
  --primary-foreground: var(--white);
  --brand: var(--dark-teal);
  --brand-foreground: var(--white);

  /* Neutrals */
  --secondary: var(--cream-bg-2);
  --secondary-foreground: var(--slate);
  --muted: var(--cream-bg-1);
  --muted-foreground: var(--black-secondary);
  --accent: var(--teal-bg-2);
  --accent-foreground: var(--dark-teal);

  /* Semantic */
  --destructive: #dc2626;
  --destructive-foreground: var(--white);

  /* Borders & inputs */
  --border: var(--grey-8);
  --input: var(--grey-16);
  --ring: var(--dark-teal);

  /* Extended palette aliases */
  --teal-bg: var(--teal-bg-1);

  /* DataOS UI — quality states */
  --dataos-surface: #f9f9f8;
  --dataos-success-bg: #dff0e8;
  --dataos-success-fg: #4a7c5f;
  --dataos-warn-bg: #fff7e6;
  --dataos-warn-fg: #d4a017;
  --dataos-fail-bg: #fde8e8;
  --dataos-fail-fg: #dc2626;

  /* Text scale */
  --text-primary: #1f1f1f;
  --text-secondary: var(--black-secondary);
  --text-tertiary: var(--black-tertiary);
  --text-quaternary: var(--black-quaternary);

  /* Charts — teal + neutral ramp */
  --chart-1: var(--dark-teal);
  --chart-2: #007072;
  --chart-3: var(--black-secondary);
  --chart-4: var(--black-tertiary);
  --chart-5: var(--teal-bg-1);

  /* Sidebar */
  --sidebar: var(--cream-bg-2);
  --sidebar-foreground: var(--slate);
  --sidebar-primary: var(--dark-teal);
  --sidebar-primary-foreground: var(--white);
  --sidebar-accent: var(--teal-bg-2);
  --sidebar-accent-foreground: var(--dark-teal);
  --sidebar-border: var(--grey-8);
  --sidebar-ring: var(--dark-teal);
}

.dark {
  /* Figma brand & surfaces — dark mode */
  --slate: #f9f8f7;
  --dark-teal: #00a8a9;
  --cream: #363634;
  --cream-bg-1: #363634;
  --cream-bg-2: #2e2e2c;
  --cream-bg-3: #242422;
  --teal-bg-1: #d6eded;
  --teal-bg-2: #1a3d3d;

  /* Figma blacks — inverted for dark surfaces */
  --black-primary: #f9f8f7;
  --black-secondary: #bfbfbf;
  --black-tertiary: #8c8c8c;
  --black-quaternary: #595959;

  /* Figma greys — dark UI ramp */
  --grey-16: #595959;
  --grey-8: #4a4a48;
  --grey-4: #363634;
  --grey-2: #2e2e2c;
  --white: #ffffff;

  --background: #242422;
  --foreground: #f9f8f7;
  --card: #2e2e2c;
  --card-foreground: #f9f8f7;
  --popover: #2e2e2c;
  --popover-foreground: #f9f8f7;

  --primary: var(--dark-teal);
  --primary-foreground: var(--white);
  --brand: var(--dark-teal);
  --brand-foreground: var(--white);

  --secondary: #363634;
  --secondary-foreground: #f9f8f7;
  --muted: #363634;
  --muted-foreground: var(--black-secondary);
  --accent: var(--teal-bg-2);
  --accent-foreground: var(--foreground);

  --destructive: #ef4444;
  --destructive-foreground: var(--white);

  --border: var(--grey-16);
  --input: var(--grey-16);
  --ring: var(--dark-teal);

  --teal-bg: var(--teal-bg-2);

  /* DataOS UI — quality states */
  --dataos-surface: #2e2e2c;
  --dataos-success-bg: #1f3d32;
  --dataos-success-fg: #8fd4a8;
  --dataos-warn-bg: #3d3220;
  --dataos-warn-fg: #e6b84d;
  --dataos-fail-bg: #3d2020;
  --dataos-fail-fg: #f87171;

  --text-primary: #f9f8f7;
  --text-secondary: var(--black-secondary);
  --text-tertiary: var(--black-tertiary);
  --text-quaternary: var(--black-quaternary);

  --chart-1: var(--dark-teal);
  --chart-2: var(--teal-bg-1);
  --chart-3: var(--black-tertiary);
  --chart-4: var(--black-quaternary);
  --chart-5: #009293;

  --sidebar: #2e2e2c;
  --sidebar-foreground: #f9f8f7;
  --sidebar-primary: var(--dark-teal);
  --sidebar-primary-foreground: var(--white);
  --sidebar-accent: var(--teal-bg-2);
  --sidebar-accent-foreground: var(--foreground);
  --sidebar-border: var(--grey-16);
  --sidebar-ring: var(--dark-teal);
}

@layer base {
  * {
    @apply border-border outline-ring/50;
  }
  body {
    @apply bg-background text-foreground;
  }
}

@layer utilities {
  .no-scrollbar {
    -ms-overflow-style: none;
    scrollbar-width: none;
  }

  .no-scrollbar::-webkit-scrollbar {
    display: none;
  }
}
